+                out_proj_weight: get(&format!("{p}.self_attn.out_proj.weight"))?,
+                out_proj_bias: get(&format!("{p}.self_attn.out_proj.bias"))?,
+                norm1_weight: get(&format!("{p}.norm1.weight"))?,
+                norm1_bias: get(&format!("{p}.norm1.bias"))?,
